import React, { useMemo, useState } from 'react';
import { createRoot } from 'react-dom/client';
import { ArrowRight, BadgeCheck, CircleAlert, Database, ExternalLink, Route, ShieldCheck, Sparkles } from 'lucide-react';
import { childFromParents, dataVersion, estimateStats, findPal, pals, parentsForTarget, passives, solveRoute, type Passive } from './calculators';
import guidePages from './guides-data.json';
import './styles.css';

type GuideKey = 'guideCombos' | 'guideTree' | 'guideOne0' | 'guideIvExplained' | 'guidePassiveSkills' | 'guideAnubis' | 'guideJetragon' | 'guideRouteExamples';
type ToolKey = 'hub' | 'breeding' | 'route' | 'iv' | 'stats' | 'passives' | 'one0' | 'data' | 'privacy' | 'terms' | GuideKey;
type ResultState = { title: string; body: string; code?: string; severity?: 'ok' | 'warn' | 'error'; details?: React.ReactNode };
type RouteMeta = { key: ToolKey; path: string; label: string; h1: string; title: string; description: string; keywords: string };
type GuidePage = (typeof guidePages)[number];

type AnalyticsEventName = 'page_view' | 'tool_success' | 'tool_error' | 'share_copy' | 'share_open' | 'beginner_section_view' | 'beginner_example_click' | 'result_explainer_view' | 'internal_nav' | 'tool_start';
type SharePayload = Record<string, string | number | boolean | undefined>;
declare global {
  interface Window {
    palcalculatorEvents?: Array<{ event: AnalyticsEventName; payload: Record<string, unknown>; ts: string }>;
    palcalculatorTrack?: (event: AnalyticsEventName, payload: Record<string, unknown>) => void;
  }
}
function deviceType() {
  const width = window.innerWidth;
  if (width < 768) return 'mobile';
  if (width < 1024) return 'tablet';
  return 'desktop';
}
function referrerHost() {
  try { return document.referrer ? new URL(document.referrer).hostname : ''; }
  catch { return ''; }
}
function analyticsContext(tool?: ToolKey) {
  const route = routes.find((r) => r.key === (tool ?? routeFromPath())) ?? routes[0];
  return {
    page_path: route.path,
    page_slug: route.key,
    device_type: deviceType(),
    referrer_host: referrerHost(),
    data_version: dataVersion.dataVersion,
  };
}
function trackEvent(event: AnalyticsEventName, payload: Record<string, unknown> = {}) {
  const safePayload = { ...analyticsContext(), ...payload };
  window.palcalculatorEvents = window.palcalculatorEvents ?? [];
  window.palcalculatorEvents.push({ event, payload: safePayload, ts: new Date().toISOString() });
  window.palcalculatorTrack?.(event, safePayload);
}
function trackToolResult(tool: ToolKey, result: ResultState, extra: Record<string, unknown> = {}) {
  trackEvent(result.severity === 'ok' ? 'tool_success' : 'tool_error', {
    ...analyticsContext(tool),
    tool_type: tool,
    result_type: result.severity === 'ok' ? 'calculator_result' : 'calculator_error',
    error_code: result.severity === 'ok' ? undefined : (result.code ?? 'UNKNOWN_ERROR'),
    recoverable: result.severity !== 'ok',
    ...extra,
  });
}
function shareUrl(tool: ToolKey, payload: SharePayload) {
  const route = routes.find((r) => r.key === tool) ?? routes[0];
  const params = new URLSearchParams();
  for (const [key, value] of Object.entries(payload)) if (value !== undefined && String(value).trim()) params.set(key, String(value));
  const path = `${route.path}${params.toString() ? `?${params.toString()}` : ''}`;
  return `${window.location.origin}${path}`;
}

const canonicalOrigin = 'https://palcalculator.com';
const routes: RouteMeta[] = [
  { key: 'hub', path: '/', label: 'Home', h1: 'PalCalculator: Palworld Breeding, IV, Stats & Passive Calculators', title: 'PalCalculator: Palworld Breeding & IV Tools', description: 'Unofficial fan-made Palworld 1.0 calculator hub for breeding routes, IV/stat checks, passive planning, and owned-Pal optimization.', keywords: 'Palworld calculator, Palworld breeding calculator, Palworld IV calculator' },
  { key: 'breeding', path: '/breeding-calculator/', label: 'Breeding', h1: 'Palworld Breeding Calculator', title: 'Palworld Breeding Calculator - Parent Pairs', description: 'Check real parent pairs, target parents, caveats, and route-solver handoffs.', keywords: 'Palworld breeding calculator, Palworld parent pairs, Palworld breeding combos' },
  { key: 'route', path: '/breeding-route-calculator/', label: 'Route', h1: 'Palworld Breeding Route Calculator', title: 'Palworld Breeding Route Calculator', description: 'Plan the shortest route found from owned Pals to a target Pal with visible constraints.', keywords: 'Palworld breeding route calculator, Palworld breeding path, owned Pals route' },
  { key: 'iv', path: '/iv-calculator/', label: 'IV', h1: 'Palworld IV Calculator', title: 'Palworld IV Calculator', description: 'Estimate IV ranges from observed stats while showing formula assumptions and unsupported modifiers.', keywords: 'Palworld IV calculator, Palworld stats, Pal IV checker' },
  { key: 'stats', path: '/stats-calculator/', label: 'Stats', h1: 'Palworld Stats Calculator', title: 'Palworld Stats Calculator', description: 'Preview expected HP, attack, and defense bands from selected base stat data.', keywords: 'Palworld stats calculator, Palworld HP attack defense, Pal stats' },
  { key: 'passives', path: '/passive-skill-calculator/', label: 'Passives', h1: 'Palworld Passive Skill Calculator', title: 'Palworld Passive Skill Calculator', description: 'Plan target passives with RNG caveats and no deterministic inheritance promises.', keywords: 'Palworld passive skill calculator, Palworld passives, passive breeding planner' },
  { key: 'one0', path: '/palworld-1-0-breeding-calculator/', label: '1.0 Breeding', h1: 'Palworld 1.0 Breeding Calculator', title: 'Palworld 1.0 Breeding Calculator', description: 'A 1.0-focused entry point that shares the breeding calculator and data freshness copy.', keywords: 'Palworld 1.0 breeding calculator, Palworld 1.0 combos, Palworld breeding' },
  { key: 'data', path: '/data-sources/', label: 'Data Sources', h1: 'PalCalculator Data Sources & Update Policy', title: 'PalCalculator Data Sources & Update Policy', description: 'Dataset version, source policy, unsupported domains, and correction workflow.', keywords: 'PalCalculator data sources, Palworld data version, Palworld calculator policy' },
  { key: 'privacy', path: '/privacy/', label: 'Privacy', h1: 'Privacy Policy', title: 'Privacy Policy | PalCalculator', description: 'How PalCalculator handles local calculator state, share URLs, hosting logs, and analytics.', keywords: 'PalCalculator privacy policy' },
  { key: 'terms', path: '/terms/', label: 'Terms', h1: 'Terms of Use', title: 'Terms of Use | PalCalculator', description: 'Unofficial fan-site terms, caveats, and acceptable use.', keywords: 'PalCalculator terms of use' },
  ...guidePages.map((guide) => ({ key: guide.key as GuideKey, path: guide.path, label: guide.label, h1: guide.h1, title: guide.title, description: guide.description, keywords: guide.keywords })),
];
const guideKeys = guidePages.map((guide) => guide.key) as GuideKey[];
const isGuideKey = (key: ToolKey): key is GuideKey => guideKeys.includes(key as GuideKey);

function upsertMeta(selector: string, create: () => HTMLMetaElement, content: string) {
  const meta = document.head.querySelector<HTMLMetaElement>(selector) ?? create();
  meta.setAttribute('content', content);
}
function updateHead(route: RouteMeta) {
  document.title = route.title;
  const canonical = document.head.querySelector<HTMLLinkElement>('link[rel="canonical"]') ?? document.head.appendChild(document.createElement('link'));
  canonical.setAttribute('rel', 'canonical');
  canonical.setAttribute('href', `${canonicalOrigin}${route.path}`);
  upsertMeta('meta[name="description"]', () => { const meta = document.createElement('meta'); meta.setAttribute('name', 'description'); return document.head.appendChild(meta); }, route.description);
  upsertMeta('meta[name="robots"]', () => { const meta = document.createElement('meta'); meta.setAttribute('name', 'robots'); return document.head.appendChild(meta); }, 'index,follow');
  upsertMeta('meta[name="keywords"]', () => { const meta = document.createElement('meta'); meta.setAttribute('name', 'keywords'); return document.head.appendChild(meta); }, route.keywords);
  upsertMeta('meta[property="og:title"]', () => { const meta = document.createElement('meta'); meta.setAttribute('property', 'og:title'); return document.head.appendChild(meta); }, route.title);
  upsertMeta('meta[property="og:description"]', () => { const meta = document.createElement('meta'); meta.setAttribute('property', 'og:description'); return document.head.appendChild(meta); }, route.description);
  upsertMeta('meta[property="og:url"]', () => { const meta = document.createElement('meta'); meta.setAttribute('property', 'og:url'); return document.head.appendChild(meta); }, `${canonicalOrigin}${route.path}`);
}

function routeFromPath(): ToolKey {
  const path = window.location.pathname.endsWith('/') ? window.location.pathname : `${window.location.pathname}/`;
  return routes.find((r) => r.path === path)?.key ?? 'hub';
}
function useRoute() {
  const [current, setCurrent] = useState<ToolKey>(routeFromPath());
  function navigate(key: ToolKey) {
    const route = routes.find((r) => r.key === key)!;
    window.history.pushState({}, '', route.path);
    setCurrent(key);
  }
  React.useEffect(() => {
    const route = routes.find((r) => r.key === current)!;
    updateHead(route);
    trackEvent('page_view', { ...analyticsContext(current), page_path: route.path, page_slug: current });
  }, [current]);
  React.useEffect(() => { const onPop = () => { const next = routeFromPath(); setCurrent(next); }; window.addEventListener('popstate', onPop); return () => window.removeEventListener('popstate', onPop); }, []);
  return { current, navigate };
}
function DataBadge() { return <div className="data-badge"><Database size={16}/><span>{dataVersion.gameVersionLabel}</span><strong>{dataVersion.dataVersion}</strong></div>; }
function Disclaimer() { return <p className="disclaimer">PalCalculator is an unofficial fan-made tool and is not affiliated with, endorsed by, sponsored by, or approved by Pocketpair or the Palworld team. Palworld and related names are trademarks or properties of their respective owners.</p>; }
function Header({ current, navigate }: { current: ToolKey; navigate: (key: ToolKey) => void }) { return <header className="site-header"><a className="brand" href="/" onClick={(e) => { e.preventDefault(); navigate('hub'); }}><img className="brand-mark" src="/brand-icon.svg" alt="" width="40" height="40" aria-hidden="true"/><span>PalCalculator</span></a><nav aria-label="Primary navigation">{routes.filter(r => ['breeding','route','iv','stats','passives','data'].includes(r.key)).map(r => <a key={r.key} href={r.path} className={current === r.key ? 'active' : ''} onClick={(e) => { e.preventDefault(); navigate(r.key); }}>{r.label}</a>)}</nav></header>; }
function focusHeroInput(selector: string) { const input = document.querySelector<HTMLElement>(selector); input?.scrollIntoView({ behavior: 'smooth', block: 'center' }); input?.focus(); }
function ToolHero({ route, navigate }: { route: (typeof routes)[number]; navigate: (key: ToolKey) => void }) { const guide = isGuideKey(route.key) ? guidePages.find((page) => page.key === route.key) : undefined; const routeHelp = 'Route planning starts from a target + owned Pals; the breeding calculator checks one parent pair or finds possible parents for a target child.'; const actions = route.key === 'hub' ? <><button className="primary" title="Plan a multi-step path from owned Pals to a target Pal" onClick={() => navigate('route')}>Plan a breeding route <ArrowRight size={18}/></button><button className="secondary" title="Check one parent pair or possible parents for a target child" onClick={() => navigate('breeding')}>Check parent pairs</button></> : route.key === 'route' ? <><button className="primary" title="Jump to the route target input on this page" onClick={() => focusHeroInput('[data-tool-input="route-target"]')}>Choose target Pal below <ArrowRight size={18}/></button><button className="secondary" title="Switch to direct parent/child lookup instead" onClick={() => navigate('breeding')}>Need parent/child lookup?</button></> : route.key === 'breeding' || route.key === 'one0' ? <><button className="primary" title="Jump to direct pair-to-child and target-to-parents lookup" onClick={() => focusHeroInput('[data-tool-input="breeding-parent-a"]')}>Check parent pairs below <ArrowRight size={18}/></button><button className="secondary" title="Use route planning when you need steps from owned Pals" onClick={() => navigate('route')}>Plan multi-step route</button></> : <><button className="primary" title="Plan a multi-step path from owned Pals to a target Pal" onClick={() => navigate('route')}>Plan a breeding route <ArrowRight size={18}/></button><button className="secondary" title="Check one parent pair or possible parents for a target child" onClick={() => navigate('breeding')}>Check parent pairs</button></>; return <section className="hero"><div><p className="eyebrow">Unofficial fan-made Palworld tool</p><h1>{route.h1}</h1><p className="hero-copy">{route.description}</p>{guide ? <div className="hero-actions"><a className="primary link-button" href={guide.primaryCta.href}>{guide.primaryCta.label} <ArrowRight size={18}/></a><a className="secondary link-button" href={guide.secondaryCta.href}>{guide.secondaryCta.label}</a></div> : <><p className="hero-help">{routeHelp}</p><div className="hero-actions">{actions}</div></>}</div><div className="hero-card"><DataBadge/><p>{pals.length} Pal records and real normal-formula breeding pairs are installed. Special combo overrides remain caveated until separately verified.</p><ul><li>Calculator UI above the fold</li><li>Copy/share URL state, no account wall</li><li>Visible caveats instead of fabricated certainty</li></ul></div></section>; }
function helperId(label: string) { return `${label.toLowerCase().replace(/[^a-z0-9]+/g, '-')}-help`; }
function PalSelect({ label, value, onChange, inputMarker, help }: { label: string; value: string; onChange: (v: string) => void; inputMarker?: string; help?: string }) { const id = helperId(label); return <label className="field"><span>{label}</span><input data-tool-input={inputMarker} list="pal-options" value={value} placeholder="Example: Anubis, Jetragon, Orserk" aria-describedby={help ? id : undefined} onChange={(e) => onChange(e.target.value)} />{help && <small id={id} className="input-help">{help}</small>}<datalist id="pal-options">{pals.map(p => <option key={p.id} value={p.displayName}/>)}</datalist></label>; }
function ResultExplainer({ tool, state }: { tool: ToolKey; state: 'success' | 'no_result' | 'invalid_input' | 'caveated' }) {
  React.useEffect(() => { trackEvent('result_explainer_view', { ...analyticsContext(tool), tool_type: tool, result_state: state, data_version: dataVersion.dataVersion }); }, [tool, state]);
  const copy: Record<string, { means: string; next: string; caveat: string }> = {
    breeding_success: { means: 'The selected parent/target lookup returned a supported breeding result in the current fan-made dataset.', next: 'Use a listed pair you already own, switch modes for a different question, or open Route if you need a path from your Pals.', caveat: 'Parent-pair lists depend on selected data, special-combo handling, and patch timing.' },
    breeding_error: { means: 'PalCalculator cannot show a supported breeding result for these inputs and this data version.', next: 'Check spelling, try selector suggestions, switch modes, or choose an editable example.', caveat: 'Unsupported data should stay unavailable instead of being filled with a guess.' },
    one0_success: { means: 'The result uses the current Palworld 1.0-focused dataset and the visible caveats on this page.', next: 'Review the data-version notes before using the pair or target list in a longer plan.', caveat: 'Palworld 1.0 data can still change with patches, corrections, and special-combo updates.' },
    route_success: { means: 'This is the shortest route PalCalculator found within your current target, owned-Pal list, and generation limit.', next: 'Breed step 1 first, then use the child as a parent in the next listed step. If too many parents are missing, add owned Pals or increase max generations.', caveat: 'This is planning guidance from a fan-made dataset, not a promise about every in-game outcome.' },
    route_error: { means: 'No supported route was found with the current constraints.', next: 'Check Pal names, add more owned Pals, increase max generations, or try the no-owned-Pals example to understand the missing-parent state.', caveat: 'A missing route can mean strict constraints, missing data, unsupported combos, or patch differences.' },
    iv_success: { means: 'Your observed stats fall into broad expected bands for the selected Pal and level.', next: 'Confirm level, visible stats, passives, souls, condenser stars, and other modifiers before deciding whether to keep or breed this Pal.', caveat: 'Rounding and unsupported modifiers can make exact IV values uncertain.' },
    iv_error: { means: 'The current inputs do not map cleanly to a supported IV estimate.', next: 'Recheck the Pal, level, visible stats, and known modifiers, then try again.', caveat: 'Some formulas or modifiers may not be fully represented in the current build.' },
    stats_success: { means: 'PalCalculator estimated broad expected stat bands for the selected Pal and level.', next: 'Use the bands as a comparison point, then check IVs or modifiers if your real Pal looks outside the expected range.', caveat: 'Expected stats depend on supported formulas, selected data, and visible modifier assumptions.' },
    stats_error: { means: 'The current dataset does not have enough supported stat information for this estimate.', next: 'Try another Pal or level, or review data-source notes before relying on the result.', caveat: 'Unsupported stat cases should show uncertainty instead of pretending the formula is complete.' },
    passives_success: { means: 'Your desired passives were recognized for planning.', next: 'Use Breeding or Route to choose candidate parents, then verify outcomes in game.', caveat: 'Passive inheritance can involve RNG, so this planner should not imply fixed odds.' },
    passives_error: { means: 'PalCalculator could not recognize the target Pal or at least one desired passive from the current data version.', next: 'Use supported passive names from this data version, check spelling, and keep the plan editable before moving to Breeding or Route.', caveat: 'Unsupported passive data should remain caveated rather than converted into odds or promises.' },
  };
  const key = `${tool}_${state === 'success' || state === 'caveated' ? 'success' : 'error'}`;
  const picked = copy[key] ?? copy.breeding_error;
  return <aside className="result-explainer" aria-label="Beginner result explanation"><div><strong>This means...</strong><p>{picked.means}</p></div><div><strong>Next step...</strong><p>{picked.next}</p></div><div><strong>Caveat...</strong><p>{picked.caveat}</p></div></aside>;
}
function ResultBox({ result, tool }: { result: ResultState; tool?: ToolKey }) { const state = result.severity === 'ok' ? 'success' : result.code?.includes('NOT_FOUND') || result.code?.includes('UNAVAILABLE') ? 'no_result' : 'invalid_input'; return <div className={`result ${result.severity ?? 'warn'}`} role="status"><div className="result-title">{result.severity === 'ok' ? <BadgeCheck/> : <CircleAlert/>}<strong>{result.title}</strong></div><p>{result.body}</p>{result.code && <code>{result.code}</code>}{result.details}{tool && <ResultExplainer tool={tool} state={state}/>}</div>; }
function ToolPanel({ title, icon, children }: { title: string; icon: React.ReactNode; children: React.ReactNode }) { return <section className="tool-panel"><div className="tool-title">{icon}<h2>{title}</h2></div><DataBadge/>{children}</section>; }
function CaveatList({ items }: { items: string[] }) { return <ul className="caveats">{items.map(i => <li key={i}>{i}</li>)}</ul>; }
function ExamplesRow({ heading, body, examples }: { heading: string; body: string; examples: Array<{ label: string; description: string; id: string; group: string; tool: ToolKey; onClick: () => void }> }) { return <section className="examples-row" aria-label={heading}><div><h3>{heading}</h3><p>{body}</p></div><div className="example-buttons">{examples.map((example) => <button className="secondary" key={example.id} title={example.description} onClick={() => { trackEvent('beginner_example_click', { ...analyticsContext(example.tool), tool_type: example.tool, example_id: example.id, example_group: example.group, data_version: dataVersion.dataVersion }); trackEvent('tool_start', { ...analyticsContext(example.tool), tool_type: example.tool, start_source: 'example_button', data_version: dataVersion.dataVersion }); example.onClick(); }}>{example.label}<small>{example.description}</small></button>)}</div></section>; }
function ShareControls({ tool, payload, resultTitle }: { tool: ToolKey; payload: SharePayload; resultTitle: string }) {
  const [status, setStatus] = useState('');
  const url = shareUrl(tool, payload);
  async function copyShareUrl() {
    try {
      await navigator.clipboard.writeText(url);
      trackEvent('share_copy', { ...analyticsContext(tool), tool_type: tool, result_type: resultTitle, copy_status: 'success' });
      setStatus('Share URL copied.');
    }
    catch {
      trackEvent('share_copy', { ...analyticsContext(tool), tool_type: tool, result_type: resultTitle, copy_status: 'fallback' });
      setStatus(url);
    }
  }
  return <div className="share-controls"><button className="secondary" onClick={copyShareUrl}>Copy/share result URL</button><a href={url} onClick={() => trackEvent('share_open', { ...analyticsContext(tool), tool_type: tool, result_type: resultTitle, source: 'button' })}>Open share URL</a>{status && <small>{status}</small>}</div>;
}

function BreedingCalculator({ one0=false }: { one0?: boolean }) {
  const [mode, setMode] = useState<'pair'|'target'>(() => window.sessionStorage.getItem('palcalculatorBeginnerExample') === 'anubis_parent_lookup' ? 'target' : 'pair'); const [a, setA] = useState('Penking'); const [b, setB] = useState('Bushi'); const [target, setTarget] = useState('Anubis');
  React.useEffect(() => { if (window.sessionStorage.getItem('palcalculatorBeginnerExample') === 'anubis_parent_lookup') window.sessionStorage.removeItem('palcalculatorBeginnerExample'); }, []);
  const result = useMemo<ResultState>(() => {
    if (mode === 'pair') { const r = childFromParents(a, b); if (!r.ok) return { title: 'Pair unavailable', body: r.error.message, code: r.error.code, severity: 'error' }; return { title: `${r.parentA.displayName} + ${r.parentB.displayName} → ${r.child.displayName}`, body: `Normal formula output for ${r.dataVersion}. Combo type: ${r.comboType}.`, code: r.ruleId, severity: 'ok', details: <CaveatList items={r.caveats.map(c => c.message)}/> }; }
    const r = parentsForTarget(target, 10); if (!r.ok) return { title: 'Target unavailable', body: r.error.message, code: r.error.code, severity: 'error' };
    return { title: `${r.resultCount} parent pairs found for ${r.target.displayName}`, body: `Showing the first ${r.pairs.length} sorted pairs.`, severity: 'ok', details: <ol className="pairs">{r.pairs.map((p, i) => <li key={i}>{p.parentA.displayName} + {p.parentB.displayName}</li>)}</ol> };
  }, [mode, a, b, target]);
  React.useEffect(() => { trackToolResult(one0 ? 'one0' : 'breeding', result, { mode, code: result.code ?? '' }); }, [result.title, result.severity, result.code, mode, one0]);
  const tool: ToolKey = one0 ? 'one0' : 'breeding';
  return <ToolPanel title={one0 ? 'Palworld 1.0 breeding workspace' : 'Breeding workspace'} icon={<Sparkles/>}><p className="tool-help">Breeding Calculator checks direct parent/child lookups: choose Pair to Child when you know two parents, or Target to Parents when you know the Pal you want. {one0 && 'Same workflow, with Palworld 1.0 data-version notes visible.'}</p><ExamplesRow heading="Try an editable breeding example" body="Click an example to fill safe demo values, then replace them with your own Pals." examples={[{ label: 'Try: Anubis parent lookup', description: 'Fills Target to Parents with Anubis so you can review possible parent pairs in the current dataset.', id: 'anubis_parent_lookup', group: 'breeding', tool, onClick: () => { setMode('target'); setTarget('Anubis'); } }, { label: 'Try: Penking + Bushi pair', description: 'Fills Pair to Child with Penking and Bushi so you can see how a direct parent lookup works.', id: 'penking_bushi_pair', group: 'breeding', tool, onClick: () => { setMode('pair'); setA('Penking'); setB('Bushi'); } }, { label: 'Try: Jetragon target lookup', description: 'Fills Target to Parents with Jetragon; if unsupported, the unavailable state stays visible instead of guessing.', id: 'jetragon_target_lookup', group: 'breeding', tool, onClick: () => { setMode('target'); setTarget('Jetragon'); } }]}/><p className="mode-help">Use Pair to Child when you know two parents. Use Target to Parents when you know the child you want.</p><div className="segmented"><button className={mode==='pair'?'selected':''} onClick={() => setMode('pair')}>Pair to Child</button><button className={mode==='target'?'selected':''} onClick={() => setMode('target')}>Target to Parents</button></div>{mode === 'pair' ? <div className="grid two"><PalSelect label="Parent A" value={a} onChange={setA} inputMarker="breeding-parent-a" help="Type one Pal you own or want to test, e.g. Penking."/><PalSelect label="Parent B" value={b} onChange={setB} help="Type the second parent, e.g. Bushi."/></div> : <PalSelect label="Target child" value={target} onChange={setTarget} inputMarker="breeding-target-child" help="Type the Pal you want to breed, e.g. Anubis."/>}<ResultBox result={result} tool={tool}/><ShareControls tool={tool} payload={{ mode, a, b, target }} resultTitle={result.title}/><CaveatList items={["Normal breeding outputs use public CombiRank values and source caveats.", "Verified special-combo override data is not claimed in this build.", "Results depend on selected data version and patch changes."]}/></ToolPanel>;
}
function RouteSolver() {
  const [target, setTarget] = useState('Anubis'); const [owned, setOwned] = useState('Penking, Bushi'); const [maxGen, setMaxGen] = useState(3);
  const result = useMemo<ResultState>(() => { const r = solveRoute(target, owned, maxGen); if (!r.ok) return { title: 'Route unavailable', body: r.error.message, code: r.error.code, severity: 'error' }; return { title: r.targetAlreadyOwned ? `${r.target.displayName} already owned` : `Route found to ${r.target.displayName}`, body: `${r.generations} generation(s), ${r.missingPals.length} missing Pal(s), ${r.alternatives.length} alternative(s). Tie rule: ${r.tieBreakRule}.`, severity: 'ok', details: <ol className="timeline">{r.steps.map(s => <li key={s.stepIndex}><span>{s.stepIndex}</span><p>{s.parentA.displayName} + {s.parentB.displayName} → {s.child.displayName}</p></li>)}</ol> }; }, [target, owned, maxGen]);
  React.useEffect(() => { trackToolResult('route', result, { code: result.code ?? '' }); }, [result.title, result.severity, result.code]);
  return <ToolPanel title="Route-first workspace" icon={<Route/>}><p className="tool-help">Route Calculator starts with the Pal you want and the Pals you own, then searches for a caveated multi-step path.</p><ExamplesRow heading="Try an editable route example" body="Use a route demo to see target, owned Pals, missing Pals, and max generations before entering your own list." examples={[{ label: 'Try: route to Anubis from Penking + Bushi', description: 'Fills target Anubis, owned Pals Penking and Bushi, and max generations 3.', id: 'anubis_route_penking_bushi', group: 'route', tool: 'route', onClick: () => { setTarget('Anubis'); setOwned('Penking, Bushi'); setMaxGen(3); } }, { label: 'Try: no owned Pals yet', description: 'Fills target Anubis with an empty owned-Pal list so you can see missing-parent guidance.', id: 'anubis_route_no_owned', group: 'route', tool: 'route', onClick: () => { setTarget('Anubis'); setOwned(''); setMaxGen(3); } }, { label: 'Try: longer route search', description: 'Keeps target Anubis and raises max generations to show broader route constraints.', id: 'anubis_route_longer_search', group: 'route', tool: 'route', onClick: () => { setTarget('Anubis'); setMaxGen(5); } }]}/><div className="grid two"><PalSelect label="Target Pal" value={target} onChange={setTarget} inputMarker="route-target" help="The Pal you want at the end of the route."/><label className="field"><span>Max generations</span><input type="number" min={1} max={8} value={maxGen} aria-describedby="max-generations-help" onChange={(e)=>setMaxGen(Number(e.target.value))}/><small id="max-generations-help" className="input-help">Higher can find longer routes, but results may be harder to follow.</small></label></div><label className="field"><span>Owned Pals (browser-local paste)</span><textarea value={owned} aria-describedby="owned-pals-help" onChange={(e)=>setOwned(e.target.value)} placeholder="Example: Penking, Bushi" /><small id="owned-pals-help" className="input-help">Optional. Paste names you already have, separated by commas or new lines. This stays browser-local in the MVP.</small>{!owned.trim() && <small className="input-help">No owned Pals entered. The route may show missing parents or a broader planning path.</small>}</label><ResultBox result={result} tool="route"/><ShareControls tool="route" payload={{ target, owned, maxGen }} resultTitle={result.title}/></ToolPanel>;
}
function IvStatsTool({ kind }: { kind: 'iv' | 'stats' }) {
  const [pal, setPal] = useState('Anubis'); const [level, setLevel] = useState(50); const [hp, setHp] = useState('500'); const [attack, setAttack] = useState('130'); const [defense, setDefense] = useState('100');
  const result = useMemo<ResultState>(() => { const r = estimateStats(pal, level, { hp: Number(hp), attack: Number(attack), defense: Number(defense) }); if (!r.ok) return { title: 'Stat estimate unavailable', body: r.error.message, code: r.error.code, severity: 'error' }; return { title: kind === 'iv' ? 'Caveated IV bands calculated' : 'Expected stat bands calculated', body: `${r.pal.displayName} level ${r.level}. Confidence: ${r.confidence}.`, code: r.formulaVersion, severity: 'ok', details: <pre>{JSON.stringify(kind === 'iv' ? r.ivRangeByStat : r.expectedStats, null, 2)}</pre> }; }, [pal, level, hp, attack, defense, kind]);
  React.useEffect(() => { trackToolResult(kind, result, { code: result.code ?? '' }); }, [result.title, result.severity, result.code, kind]);
  const isIv = kind === 'iv';
  return <ToolPanel title={isIv ? 'IV estimate workspace' : 'Stats range workspace'} icon={<BadgeCheck/>}><p className="tool-help">{isIv ? 'IV Calculator estimates broad stat-quality bands from the Pal, level, and visible stats you enter.' : 'Stats Calculator shows broad expected HP, Attack, and Defense bands for a selected Pal and level.'}</p><ExamplesRow heading={isIv ? 'Try an editable IV example' : 'Try an editable stats example'} body={isIv ? 'Use a safe demo to learn the fields, then replace the values with your own in-game stats.' : 'Start with a level 50 demo, then change the Pal or level to compare expected stat bands.'} examples={isIv ? [{ label: 'Try: level 50 Anubis IV bands', description: 'Fills Anubis at level 50 with safe demo stat values so you can review broad IV bands and caveats.', id: 'anubis_iv_level_50', group: 'iv', tool: 'iv', onClick: () => { setPal('Anubis'); setLevel(50); setHp('500'); setAttack('130'); setDefense('100'); } }, { label: 'Try: modifier caveat check', description: 'Shows why level, visible stats, and modifiers should be checked before trusting a narrow estimate.', id: 'iv_modifier_caveat_check', group: 'iv', tool: 'iv', onClick: () => { setPal('Anubis'); setLevel(50); setHp('450'); setAttack('120'); setDefense('95'); } }] : [{ label: 'Try: Anubis expected stats', description: 'Fills Anubis at level 50 so you can compare broad expected HP, Attack, and Defense bands.', id: 'anubis_stats_level_50', group: 'stats', tool: 'stats', onClick: () => { setPal('Anubis'); setLevel(50); setHp('500'); setAttack('130'); setDefense('100'); } }, { label: 'Try: change level comparison', description: 'Starts with Anubis and invites you to change level to see how expected bands move.', id: 'stats_level_comparison', group: 'stats', tool: 'stats', onClick: () => { setPal('Anubis'); setLevel(30); setHp('360'); setAttack('95'); setDefense('75'); } }]}/><div className="grid two"><PalSelect label="Pal" value={pal} onChange={setPal} help="Choose the Pal whose stats you are checking."/><label className="field"><span>Level</span><input type="number" min={1} max={60} value={level} aria-describedby={`${kind}-level-help`} onChange={(e)=>setLevel(Number(e.target.value))}/><small id={`${kind}-level-help`} className="input-help">{isIv ? 'Use the in-game level shown for that Pal.' : 'Use the level you want to preview or compare.'}</small></label></div><div className="grid three"><label className="field"><span>Observed HP</span><input value={hp} onChange={(e)=>setHp(e.target.value)} inputMode="numeric" /><small className="input-help">Enter the visible in-game HP value. If upgrades or modifiers apply, read the caveat before trusting exact bands.</small></label><label className="field"><span>Observed Attack</span><input value={attack} onChange={(e)=>setAttack(e.target.value)} inputMode="numeric" /><small className="input-help">Enter the visible in-game Attack value. Passive skills and modifiers can widen the estimate.</small></label><label className="field"><span>Observed Defense</span><input value={defense} onChange={(e)=>setDefense(e.target.value)} inputMode="numeric" /><small className="input-help">Enter the visible in-game Defense value. Rounding and modifiers can make exact values uncertain.</small></label></div><ResultBox result={result} tool={kind}/><ShareControls tool={kind} payload={{ pal, level, hp, attack, defense }} resultTitle={result.title}/><CaveatList items={["Outputs are broad ranges when rounding/modifiers create uncertainty.", "Exact Palworld reverse-engineering with all modifiers is unsupported in this build.", "No perfect IV or 100% accuracy claims are used."]}/></ToolPanel>;
}
function PassivePlanner() { const [target, setTarget] = useState('Anubis'); const [desired, setDesired] = useState('Artisan, Serious'); const targetPal = findPal(target); const recognizedPassives = desired.split(',').map(s => s.trim().toLowerCase()).filter(Boolean).map(x => passives.find(p => p.displayName.toLowerCase() === x || p.id === x)).filter((p): p is Passive => Boolean(p)); const recognizedCount = recognizedPassives.length; const result: ResultState = { title: !targetPal ? 'Target needs review' : recognizedCount > 0 ? 'Passive plan captured' : 'No desired passives recognized', body: `${recognizedCount} desired passive(s) recognized. Candidate route logic stays caveated because inheritance odds are not claimed.`, code: !targetPal ? 'INVALID_PAL' : recognizedCount > 0 ? 'PASSIVE_RNG_CAVEATED' : 'PASSIVE_NAMES_UNSUPPORTED', severity: targetPal && recognizedCount > 0 ? 'ok' : 'error', details: recognizedCount === 0 ? <CaveatList items={[`Use supported passive names from this data version: ${passives.map(p => p.displayName).join(', ')}.`]}/> : undefined }; React.useEffect(() => { trackToolResult('passives', result, { code: result.code ?? '' }); }, [result.title, result.severity, result.code]); return <ToolPanel title="Passive planner shell" icon={<ShieldCheck/>}><p className="tool-help">Passive Skill Calculator helps you capture desired passives for planning, while keeping inheritance RNG caveats visible.</p><ExamplesRow heading="Try an editable passive example" body="Use a passive-planning demo to learn the format, then replace the target and desired skills." examples={[{ label: 'Try: Artisan + Serious passive plan', description: 'Fills target Anubis with Artisan and Serious as desired passives for a work-speed planning example.', id: 'artisan_serious_passive_plan', group: 'passives', tool: 'passives', onClick: () => { setTarget('Anubis'); setDesired('Artisan, Serious'); } }, { label: 'Try: Swift mobility passive plan', description: 'Fills target Anubis with Swift as a supported mobility passive in the current dataset.', id: 'swift_mobility_passive_plan', group: 'passives', tool: 'passives', onClick: () => { setTarget('Anubis'); setDesired('Swift'); } }]}/><div className="grid two"><PalSelect label="Target Pal" value={target} onChange={setTarget} help="The Pal you eventually want with these passives."/><label className="field"><span>Desired passives</span><input value={desired} onChange={(e)=>setDesired(e.target.value)} placeholder="Example: Artisan, Serious" aria-describedby="desired-passives-help"/><small id="desired-passives-help" className="input-help">Type passive names separated by commas, e.g. Artisan, Serious.</small></label></div><ResultBox result={result} tool="passives"/><ShareControls tool="passives" payload={{ target, desired }} resultTitle={result.title}/><CaveatList items={["Passive inheritance can involve RNG.", "Use as planning guidance, not certainty.", "Candidate parents/routes use the breeding route calculator plus caveats."]}/></ToolPanel>; }
function GuideLinks({ navigate }: { navigate: (key: ToolKey) => void }) { return <section className="content guide-links"><h2>Palworld breeding guides</h2><p>Use these guides when you want explanation before opening a calculator. Each page keeps fan-made data and Palworld 1.0 caveats visible.</p><div className="cards">{guidePages.map((guide) => <a className="card" key={guide.key} href={guide.path} onClick={(e) => { e.preventDefault(); trackEvent('internal_nav', { from_page: routeFromPath(), to_page: guide.path, link_context: 'guide_card' }); navigate(guide.key as GuideKey); }}><h3>{guide.h1}</h3><p>{guide.description}</p><span>Read guide <ArrowRight size={14}/></span></a>)}</div></section>; }
function BeginnerHowToSection({ navigate }: { navigate: (key: ToolKey) => void }) { React.useEffect(() => { trackEvent('beginner_section_view', { page_slug: 'hub', section_id: 'how-to-use-palcalculator', device_type: deviceType(), data_version: dataVersion.dataVersion }); }, []); return <section id="how-to-use-palcalculator" className="content beginner-howto"><p className="eyebrow">Beginner path</p><h2>How to use PalCalculator</h2><p>New to Palworld breeding calculators? Start with a goal, try an editable example, then read the result notes before spending resources.</p><p>Pick what you know now. PalCalculator can help with parent pairs, multi-step routes, IV/stat checks, and passive planning while keeping fan-made data caveats visible.</p><div className="cards three"><article className="card"><span className="step-number">1</span><h3>Choose your goal</h3><p>Know the Pal you want? Start with Route or Target to Parents. Know two parents? Use Pair to Child. Checking a Pal you own? Use IV, Stats, or Passives.</p><small>Route = plan steps from Pals you own to a target Pal. Pair = check what two parents make, or find possible parents for a target child. IV/Stats = estimate stat quality and expected bands. Passives = plan desired skills with RNG caveats.</small><button className="secondary" title="Jump to the PalCalculator tool cards" onClick={() => document.querySelector('.cards')?.scrollIntoView({ behavior: 'smooth', block: 'start' })}>Help me choose a tool</button></article><article className="card"><span className="step-number">2</span><h3>Try an example</h3><p>Use safe prefilled examples like Anubis parent lookup, a route demo, level 50 stat bands, or Artisan + Serious passive planning.</p><small>Examples are demos you can edit. They are not claims about the best path for every player.</small><button className="secondary" title="Open an editable Anubis parent lookup example" onClick={() => { window.sessionStorage.setItem('palcalculatorBeginnerExample', 'anubis_parent_lookup'); trackEvent('beginner_example_click', { tool_type: 'breeding', example_id: 'anubis_parent_lookup', example_group: 'homepage', page_slug: 'hub', data_version: dataVersion.dataVersion }); navigate('breeding'); }}>Try Anubis example</button></article><article className="card"><span className="step-number">3</span><h3>Read what it means</h3><p>After a result appears, check the beginner notes: This means..., Next step..., and Caveat....</p><small>Use the result as planning guidance, then verify caveats before committing rare Pals or resources.</small><button className="secondary" title="Learn how to read PalCalculator result notes" onClick={() => navigate('guideRouteExamples')}>See result guide</button></article></div><p className="footer-note">Fan-made Palworld helper. Results depend on the selected data version, supported formulas, special-combo handling, and game patches.</p></section>; }
function Hub({ navigate }: { navigate: (key: ToolKey) => void }) { return <><div className="cards">{routes.filter(r => ['breeding','route','iv','stats','passives','one0'].includes(r.key)).map(r => <button className="card" key={r.key} onClick={() => navigate(r.key)}><h3>{r.h1}</h3><p>{r.description}</p><span>{r.label} <ArrowRight size={14}/></span></button>)}</div><BeginnerHowToSection navigate={navigate}/><section className="content"><h2>Production data status</h2><p>This build replaces example-only data with a Palworld 1.0 public-web dataset: {pals.length} Pals, normal formula breeding pairs, aliases, passive seed data, selected base stats, and caveated stat formulas.</p></section><GuideLinks navigate={navigate}/></>; }
const guideCtas: Record<GuideKey, { heading: string; body: string; primaryHelper: string; secondaryHelper: string }> = { guideCombos: { heading: 'Check a combo in the calculator', body: 'Use Pair to Child for two known parents, or Target to Parents when you know the Pal you want.', primaryHelper: 'Open Breeding Calculator, choose Target to Parents, and try: Anubis.', secondaryHelper: 'Use Pair to Child and try: Penking + Bushi.' }, guideTree: { heading: 'Plan a route instead of one combo', body: 'Use Route when a direct parent pair is not enough and you need steps from Pals you own.', primaryHelper: 'Open Route Calculator and try target Anubis with owned Pals Penking, Bushi and max generations 3.', secondaryHelper: 'Use Breeding Calculator if you only need one parent/child lookup.' }, guideOne0: { heading: 'Use the 1.0 breeding workflow', body: 'Check the same parent/child workflow with Palworld 1.0 data-version notes visible.', primaryHelper: 'Try Target to Parents with Anubis, then review data-version caveats before following the result.', secondaryHelper: 'Check source and update notes before committing to a long breeding plan.' }, guideIvExplained: { heading: 'Try an IV estimate with caveats visible', body: 'Use a level 50 Anubis demo to see how observed stats become broad IV bands.', primaryHelper: 'Open IV Calculator and try: Anubis, level 50, with safe demo stats or your own visible stats.', secondaryHelper: 'Use Stats Calculator when you want expected HP, Attack, and Defense bands instead of an IV estimate.' }, guidePassiveSkills: { heading: 'Plan passives without hiding RNG', body: 'Choose desired passives for planning, then use breeding tools to look for candidate parents.', primaryHelper: 'Open Passive Skill Calculator and try target Anubis with desired passives Artisan, Serious.', secondaryHelper: 'Use Route after choosing passives if you need a path from Pals you own.' }, guideAnubis: { heading: 'Start with an Anubis calculator example', body: 'Use Anubis as the target, then decide whether you need direct parent pairs or a route from owned Pals.', primaryHelper: 'Open Breeding Calculator, choose Target to Parents, and try: Anubis.', secondaryHelper: 'Open Route Calculator and try Anubis with owned Pals you actually have.' }, guideJetragon: { heading: 'Check Jetragon support before planning', body: 'Use the calculator to verify whether Jetragon is supported in the current dataset before following a long plan.', primaryHelper: 'Open Breeding Calculator, choose Target to Parents, and try: Jetragon. If unsupported, keep the unavailable state visible.', secondaryHelper: 'Check data-version notes before treating any Jetragon workflow as usable.' }, guideRouteExamples: { heading: 'Try a route example in the calculator', body: 'Use a route demo to see target, owned Pals, missing parents, and generation limits in context.', primaryHelper: 'Open Route Calculator and try target Anubis with owned Pals Penking, Bushi and max generations 3.', secondaryHelper: 'Use Breeding Calculator if you only need one parent-pair lookup.' } };
function GuidePage({ page }: { page: GuidePage }) { const faqJson = { '@context': 'https://schema.org', '@type': 'FAQPage', mainEntity: page.faqs.map((faq) => ({ '@type': 'Question', name: faq.question, acceptedAnswer: { '@type': 'Answer', text: faq.answer } })) }; const articleJson = { '@context': 'https://schema.org', '@type': 'TechArticle', headline: page.h1, description: page.description, url: `${canonicalOrigin}${page.path}`, isPartOf: { '@type': 'WebSite', name: 'PalCalculator', url: canonicalOrigin } }; const cta = guideCtas[page.key as GuideKey]; return <article className="content guide-page"><script type="application/ld+json" dangerouslySetInnerHTML={{ __html: JSON.stringify(articleJson) }} /><script type="application/ld+json" dangerouslySetInnerHTML={{ __html: JSON.stringify(faqJson) }} />{page.intro.map((paragraph) => <p key={paragraph}>{paragraph}</p>)}<div className="cta-panel"><p className="eyebrow">Try this in PalCalculator</p><h2>{cta.heading}</h2><p>{cta.body}</p><a className="primary link-button" href={page.primaryCta.href} onClick={() => trackEvent('internal_nav', { from_page: page.path, to_page: page.primaryCta.href, link_context: 'guide_primary_cta' })}>{page.primaryCta.label} <ArrowRight size={18}/></a><p className="cta-helper">{cta.primaryHelper}</p><a className="secondary link-button" href={page.secondaryCta.href} onClick={() => trackEvent('internal_nav', { from_page: page.path, to_page: page.secondaryCta.href, link_context: 'guide_secondary_cta' })}>{page.secondaryCta.label}</a><p className="cta-helper">{cta.secondaryHelper}</p></div>{page.sections.map((section) => <section key={section.heading}><h2>{section.heading}</h2>{section.paragraphs.map((paragraph) => <p key={paragraph}>{paragraph}</p>)}</section>)}<section><h2>Related PalCalculator tools</h2><ul>{page.links.map((link) => <li key={link.href}><a href={link.href}>{link.label}</a></li>)}</ul></section><section><h2>FAQ</h2>{page.faqs.map((faq) => <details key={faq.question} open><summary>{faq.question}</summary><p>{faq.answer}</p></details>)}</section></article>; }
function DataSources() { return <section className="content"><h2>Data source status</h2><dl><dt>Game target</dt><dd>{dataVersion.gameVersionLabel}</dd><dt>Dataset build</dt><dd>{dataVersion.dataVersion}</dd><dt>Last updated</dt><dd>{dataVersion.lastUpdated}</dd><dt>Included domains</dt><dd>{dataVersion.includedDomains.join(', ')}.</dd><dt>Unsupported now</dt><dd>{dataVersion.unsupportedDomains.join(', ')}.</dd><dt>Correction path</dt><dd id="corrections">Use the owner support/contact path before launch; corrections should include Pal name, game version, source link, and reproduction notes.</dd></dl><h3>Sources</h3><ul>{dataVersion.sourceRefs.map((s) => <li key={s.id}><a href={s.url}>{s.label}</a> — {s.category}. {s.notes}</li>)}</ul><p>Competitor/community pages are not treated as official; outputs carry source/version caveats and unsupported domains are stated instead of guessed.</p></section>; }
function Privacy() { return <section className="content"><h2>Privacy summary</h2><p>PalCalculator is a static, Cloudflare-first calculator hub. MVP inputs such as selected Pals, owned-Pal text, stat fields, and passive choices are handled in the browser UI unless a later owner-approved backend design changes that.</p><ul><li>No account or payment is required for P0 calculators.</li><li>No server-side save-file or raw Palbox upload is implemented.</li><li>Share URLs may include selected Pals or settings; do not share private state.</li><li>Analytics may use Cloudflare Web Analytics for aggregate page views and first-party calculator events for diagnostics; event payloads avoid raw inputs, share URLs, emails, IP addresses, tokens, and save data.</li><li>Advertising may use Google AdSense, which can load Google ad scripts and use cookies or similar technologies for ad delivery, measurement, fraud prevention, and personalization controls.</li></ul></section>; }
function Terms() { return <section className="content"><h2>Unofficial fan-site terms</h2><p>This site is provided as an independent fan tool. References to Palworld, Pal names, game mechanics, or related terms are for identification and compatibility purposes only.</p><ul><li>Do not rely on calculator output as guaranteed, official, always current, or perfectly accurate.</li><li>Results depend on selected data versions, source quality, game patches, formulas, modifiers, and RNG.</li></ul></section>; }
function JsonLd() { const json = { '@context': 'https://schema.org', '@type': 'SoftwareApplication', name: 'PalCalculator', applicationCategory: 'GameApplication', operatingSystem: 'Web', offers: { '@type': 'Offer', price: '0', priceCurrency: 'USD' }, description: 'Unofficial fan-made Palworld calculator hub for breeding routes, IV/stat checks, passive planning, and owned-Pal optimization.' }; return <script type="application/ld+json" dangerouslySetInnerHTML={{ __html: JSON.stringify(json) }} />; }
function App() { const { current, navigate } = useRoute(); const route = routes.find(r => r.key === current)!; const guide = isGuideKey(current) ? guidePages.find(page => page.key === current) : undefined; return <><JsonLd/><Header current={current} navigate={navigate}/><main><ToolHero route={route} navigate={navigate}/>{current === 'hub' && <Hub navigate={navigate}/>} {current === 'breeding' && <><BreedingCalculator/><GuideLinks navigate={navigate}/></>} {current === 'one0' && <><BreedingCalculator one0/><GuideLinks navigate={navigate}/></>} {current === 'route' && <><RouteSolver/><GuideLinks navigate={navigate}/></>} {current === 'iv' && <><IvStatsTool kind="iv"/><GuideLinks navigate={navigate}/></>} {current === 'stats' && <><IvStatsTool kind="stats"/><GuideLinks navigate={navigate}/></>} {current === 'passives' && <><PassivePlanner/><GuideLinks navigate={navigate}/></>} {current === 'data' && <><DataSources/><GuideLinks navigate={navigate}/></>} {current === 'privacy' && <Privacy/>} {current === 'terms' && <Terms/>} {guide && <GuidePage page={guide}/>}</main><footer><Disclaimer/><div className="footer-links">{routes.filter(r => ['data','privacy','terms'].includes(r.key)).map(r => <a key={r.key} href={r.path} onClick={(e) => { e.preventDefault(); navigate(r.key); }}>{r.label}</a>)}{guidePages.map(guide => <a key={guide.key} href={guide.path} onClick={(e) => { e.preventDefault(); navigate(guide.key as GuideKey); }}>{guide.label}</a>)}<a href="/sitemap.xml">Sitemap <ExternalLink size={12}/></a></div></footer></>; }

createRoot(document.getElementById('root')!).render(<React.StrictMode><App /></React.StrictMode>);
